package agent

import "strings"

// OperatorCancelReason marks a landing preserved because the operator
// cancelled the attempt mid-flight via /api/beads/<id>/cancel. ADR-022
// §Cancel SLA: the worker aborts at the next safe point (between LLM turns /
// git ops) and emits a preserved_for_review result with this exact reason.
const OperatorCancelReason = "operator_cancel"

// PushFailedReasonPrefix is the canonical Reason prefix written by the
// landing layer when `git push` rejects the new tip after a local merge or
// fast-forward succeeded. ClassifyExecuteBeadStatus matches on this prefix
// to map a merged-locally-but-not-pushed outcome to push_failed instead of
// success, so the bead stays open.
const PushFailedReasonPrefix = "landed locally; push failed:"

// PushConflictReasonPrefix marks a more specific failure mode than
// PushFailedReasonPrefix: the local push was rejected because the remote
// advanced, the loop attempted an automatic pull/merge to recover, and the
// merge produced a conflict the loop cannot resolve. The bead is parked for
// human review with a short cooldown rather than a year-long park.
const PushConflictReasonPrefix = "landed locally; push conflict:"

// FailureMode constants classify *why* an execution did not land cleanly.
// They are orthogonal to Outcome/Status: a single failed attempt carries one
// outcome (e.g. preserved) and one failure mode (e.g. merge_conflict) so
// measurement surfaces can aggregate failures by cause.
const (
	FailureModeContextOverflow                = "context_overflow"
	FailureModeMergeConflict                  = "merge_conflict"
	FailureModeTestFailure                    = "test_failure"
	FailureModeBuildFailure                   = "build_failure"
	FailureModeTimeout                        = "timeout"
	FailureModeAuthError                      = "auth_error"
	FailureModeNoChanges                      = "no_changes"
	FailureModeNoEvidenceProduced             = "no_evidence_produced"
	FailureModeRatchetMiss                    = "ratchet_miss"
	FailureModeNoViableProvider               = "no_viable_provider"
	FailureModeProviderConnectivity           = "provider_connectivity"
	FailureModeServerUnavailable              = "server_unavailable"
	FailureModeHarnessNotInstalled            = "harness_not_installed"
	FailureModeBlockedByPassthroughConstraint = "blocked_by_passthrough_constraint"
	FailureModeAgentPowerUnsatisfied          = "agent_power_unsatisfied"
	FailureModeLockContention                 = "lock_contention"
	FailureModeWorktreeLost                   = "worktree_lost"
	// FailureModeRouteResolutionTimeout classifies an attempt that was parked
	// because route resolution / routing preflight exceeded the configured
	// route-resolution timeout. The lease is released and the bead is flagged
	// for operator attention rather than auto-retried (ddx-d8970a7b).
	FailureModeRouteResolutionTimeout = "route_resolution_timeout"
	// FailureModeProgressWatchdog classifies an attempt the progress watchdog
	// terminated because phase-empty heartbeats (harness/model/route all empty)
	// persisted past the phase budget. The worker appeared fresh to the
	// liveness TTL while making no forward progress, so the lease is released
	// and the bead is flagged for operator attention (ddx-dc23f001, parent
	// ddx-8f2e0ebf criterion B).
	FailureModeProgressWatchdog = "progress_watchdog"
	// FailureModeConsecutiveWedge classifies a bead the consecutive-wedge guard
	// stopped re-claiming because it wedged (route_resolution_timeout or
	// progress_watchdog) on consecutive claims up to the threshold. The bead is
	// parked to proposed for operator attention so the single-threaded worker
	// keeps draining the rest of the queue instead of re-wedging the same bead
	// indefinitely (ddx-9714eaac, parent ddx-8f2e0ebf criterion E).
	FailureModeConsecutiveWedge = "consecutive_wedge"
	// FailureModeAttemptIntegrity classifies an attempt that produced commits
	// and a clean agent exit but failed DDx's structured post-agent integrity
	// validation (post-commit mutation, empty pre-commit gate evidence, or
	// uncommitted tracked changes after the implementation commit). It is
	// distinct from implementation/agent failures so operators can tell a DDx
	// validation rejection apart from a genuine task failure (ddx-725b65b4).
	FailureModeAttemptIntegrity = "attempt_integrity"
	FailureModeUnknown          = "unknown"
)

// ResourceExhaustedStopMessage is the operator-visible message emitted when
// execution must stop because the host cannot safely continue draining the
// queue.
const ResourceExhaustedStopMessage = "resource exhausted after cleanup; stopping work loop"

// ClassifyFailureMode derives a failure_mode for a worker-level result from
// its outcome, exit code, and error message. Returns "" when the outcome is
// task_succeeded (success carries no failure mode). task_no_changes always
// maps to FailureModeNoChanges regardless of error text.
//
// For task_failed (or non-zero exit code), the error message is scanned for
// well-known substrings. The order matters: context/auth/timeout patterns
// are checked before generic test/build patterns so a "test timed out"
// classifies as timeout rather than test_failure. Anything unrecognised
// maps to FailureModeUnknown so aggregates never hide a missed pattern.
func ClassifyFailureMode(outcome string, exitCode int, errMsg string) string {
	switch outcome {
	case ExecuteBeadOutcomeTaskSucceeded:
		if exitCode == 0 {
			return ""
		}
		// Degenerate: success outcome with non-zero exit. Treat as unknown
		// failure rather than success so the aggregate flags the anomaly.
	case ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	}

	lower := strings.ToLower(errMsg)
	switch {
	case IsLockContentionError(errMsg):
		return FailureModeLockContention
	case IsWorktreeLostError(errMsg):
		return FailureModeWorktreeLost
	case containsAny(lower,
		"passthrough constraint unsatisfiable",
		"passthrough constraint:",
		"max_power is less than min_power",
		"max_power exceeds min_power",
		"must be less than max_power",
		"no viable routing candidate for pins",
		"harness cannot satisfy power constraint",
		"harness pin incompatible with power bounds",
		"model pin incompatible with power bounds",
		"provider pin incompatible with power bounds"):
		return FailureModeBlockedByPassthroughConstraint
	case containsAny(lower,
		"agent power unsatisfied",
		"no model meets min_power",
		"no model with power >=",
		"minimum power not achievable",
		"min_power constraint cannot be satisfied"):
		return FailureModeAgentPowerUnsatisfied
	case containsAny(lower,
		"executable file not found in $path",
		"executable file not found",
		"no such file or directory") &&
		containsAny(lower, "exec:", "harness", "claude", "agent", "codex", "gemini"):
		return FailureModeHarnessNotInstalled
	case containsAny(lower,
		"no viable harness",
		"no harness configured",
		"failed to initialize routing service",
		"resolveroute:",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint",
		"no viable provider"):
		return FailureModeNoViableProvider
	case isServerTransportFailureText(lower):
		return FailureModeServerUnavailable
	case containsAny(lower,
		"context length",
		"context_length_exceeded",
		"context window",
		"maximum context",
		"prompt is too long",
		"prompt too long",
		"token limit",
		"too many tokens",
		"exceeds the context"):
		return FailureModeContextOverflow
	case containsAny(lower,
		"unauthorized",
		"401 unauthorized",
		"invalid api key",
		"invalid_api_key",
		"authentication failed",
		"authentication_error",
		"no api key",
		"missing api key",
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"rate limit",
		"rate_limit",
		"429"):
		return FailureModeAuthError
	case containsAny(lower,
		"timeout",
		"timed out",
		"context deadline exceeded",
		"deadline exceeded",
		"signal: killed"):
		return FailureModeTimeout
	case containsAny(lower,
		"merge conflict",
		"ff-merge not possible",
		"merge failed",
		"automatic merge failed"):
		return FailureModeMergeConflict
	case containsAny(lower,
		"build failed",
		"compilation failed",
		"compile error",
		"compilation error",
		"cannot find package",
		"undefined:",
		"undefined reference",
		"syntax error"):
		return FailureModeBuildFailure
	case containsAny(lower,
		"test failed",
		"tests failed",
		"--- fail:",
		"assertion failed",
		"test failure"):
		return FailureModeTestFailure
	}
	if outcome == ExecuteBeadOutcomeTaskFailed && errMsg != "" {
		return FailureModeUnknown
	}
	if exitCode != 0 {
		return FailureModeUnknown
	}
	return ""
}

// IsWorktreeLostError reports whether errMsg describes the execute-bead
// infrastructure losing the isolated attempt worktree before DDx could inspect
// its HEAD. This deliberately requires both a HEAD/worktree signal and a
// missing-path signal so generic harness "no such file" errors do not get
// bucketed as infrastructure loss.
func IsWorktreeLostError(errMsg string) bool {

---
func IsWorktreeLostError(errMsg string) bool {
	lower := strings.ToLower(errMsg)
	hasHeadSignal := containsAny(lower,
		"failed to read worktree head",
		"git rev-parse head",
		"worktree path missing")
	hasMissingPathSignal := containsAny(lower,
		"chdir",
		"no such file or directory",
		"cannot access",
		"does not exist")
	return hasHeadSignal && hasMissingPathSignal
}

// containsAny reports whether s contains any of the given substrings. s is
// assumed to already be lower-cased by the caller.
func containsAny(s string, needles ...string) bool {
	for _, n := range needles {
		if n == "" {
			continue
		}
		if strings.Contains(s, n) {
			return true
		}
	}
	return false
}

// classifyLandingFailureMode computes the final failure_mode for a result
// after the orchestrator has made its landing decision. It prefers
// landing-specific signals (merge conflict, gate failure) over the worker's
// classification and falls back to workerMode for worker-level failures
// (agent execution failed, context overflow, etc.). Returns "" when the
// bead merged cleanly.
func classifyLandingFailureMode(landingOutcome, landingReason string, gateResults []GateCheckResult, workerMode string) string {
	switch landingOutcome {
	case "merged":
		return ""
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	case "error":
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	case "preserved":
		switch {
		case landingReason == "merge conflict" || landingReason == "merge failed" || landingReason == "ff-merge not possible":
			return FailureModeMergeConflict
		case landingReason == "post-run checks failed", strings.HasPrefix(landingReason, PreMergeChecksReason):
			return classifyGateFailure(gateResults)
		case landingReason == RatchetPreserveReason:
			return FailureModeRatchetMiss
		case landingReason == AttemptIntegrityPreserveReason:
			return FailureModeAttemptIntegrity
		case landingReason == OperatorCancelReason:
			return ""
		}
		// Other preserved reasons (e.g. "agent execution failed",
		// "--no-merge specified") defer to the worker's classification.
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	}
	if workerMode != "" {
		return workerMode
	}
	return FailureModeUnknown
}

// classifyGateFailure inspects failed gate results to distinguish
// build_failure from test_failure. Gate definitions that fail to compile
// before running (go build, tsc, cargo build) typically surface build
// diagnostics in stderr; test runners surface test failure markers. When
// ambiguous, defaults to test_failure since the post-run checks gate is
// test-oriented by convention.
func classifyGateFailure(gateResults []GateCheckResult) string {
	for _, gr := range gateResults {
		if gr.Status != "fail" {
			continue
		}
		combined := strings.ToLower(gr.Stdout + "\n" + gr.Stderr)
		if containsAny(combined,
			"build failed",
			"compilation failed",
			"compile error",
			"compilation error",
			"cannot find package",
			"undefined:",
			"undefined reference",
			"syntax error") {
			return FailureModeBuildFailure
		}
	}
	return FailureModeTestFailure
}

// Worker-level outcome constants — set by ExecuteBead() on the result.
// The parent orchestrator (LandBeadResult + ApplyLandingToResult) then
// overwrites Outcome and Status with the landing decision.
const (
	ExecuteBeadOutcomeTaskSucceeded  = "task_succeeded"
	ExecuteBeadOutcomeTaskFailed     = "task_failed"
	ExecuteBeadOutcomeTaskNoChanges  = "task_no_changes"
	ExecuteBeadOutcomeTaskNoEvidence = "task_no_evidence"
)

// Status constants — used by the loop and other consumers of ExecuteBeadReport.
// These map to specific close/unclaim behaviors in ExecuteBeadWorker.
const (
	ExecuteBeadStatusStructuralValidationFailed = "structural_validation_failed"
	ExecuteBeadStatusExecutionFailed            = "execution_failed"
	ExecuteBeadStatusPostRunCheckFailed         = "post_run_check_failed"
	ExecuteBeadStatusRatchetFailed              = "ratchet_failed"
	ExecuteBeadStatusLandConflict               = "land_conflict"
	ExecuteBeadStatusPushFailed                 = "push_failed"
	ExecuteBeadStatusPushConflict               = "push_conflict"
	ExecuteBeadStatusPreservedNeedsReview       = "preserved_needs_review"
	ExecuteBeadStatusNoEvidenceProduced         = "no_evidence_produced"
	ExecuteBeadStatusNoChanges                  = "no_changes"
	ExecuteBeadStatusAlreadySatisfied           = "already_satisfied"
	ExecuteBeadStatusSuccess                    = "success"
	ExecuteBeadStatusResourceExhausted          = "resource_exhausted"

	// ExecuteBeadStatusDeclinedNeedsDecomposition is a structured outcome
	// signalling that the executor inspected the bead and concluded it cannot
	// be delivered in a single pass — typically because the scope is
	// epic-sized and must first be broken into sub-beads. It is distinct
	// from no_changes (which means "I tried and there was nothing to change")
	// and from execution_failed (which means the agent or harness errored).
	//
	// The loop treats this status as terminal-for-loop: it parks the bead
	// with a long cooldown and records the recommended sub-beads as a
	// structured `decomposition-recommendation` event. No further attempts
	// happen until an operator clears the cooldown (e.g. via
	// `ddx bead cooldown clear`) or splits the bead.
	ExecuteBeadStatusDeclinedNeedsDecomposition = "declined_needs_decomposition"

	// Post-merge review outcomes. The bead was merged, then reviewed;
	// the review returned a non-APPROVE verdict and the bead was reopened.
	ExecuteBeadStatusReviewRequestChanges = "review_request_changes"
	ExecuteBeadStatusReviewBlock          = "review_block"
	ExecuteBeadStatusReviewMalfunction    = "review_malfunction"

	// ExecuteBeadStatusReviewRequestClarification is set when the reviewer
	// returns REQUEST_CLARIFICATION — it cannot adjudicate one or more
	// needs-judgment AC items without operator input. The bead moves to
	// status=proposed (operator lane) without blocking the drain queue.
	ExecuteBeadStatusReviewRequestClarification = "review_request_clarification"

	// ExecuteBeadStatusLandConflictUnresolvable is set when work
	// attempted 3-way ort auto-resolution and (if configured) a focused
	// conflict-resolve agent run for a preserved iteration, and both failed.
	// The bead is parked under LandConflictCooldown for operator review.
	ExecuteBeadStatusLandConflictUnresolvable = "land_conflict_unresolvable"

	// ExecuteBeadStatusLandConflictOperatorRequired is set when the focused
	// conflict-resolve agent escalated to BLOCKING — the conflict requires
	// operator judgment, not automated retry. The bead moves to status=proposed
	// with a kind:land-conflict-operator-required event.
	ExecuteBeadStatusLandConflictOperatorRequired = "land_conflict_operator_required"

	// ExecuteBeadStatusReviewTerminalBlock is set when a BLOCK review verdict
	// is classified as a terminal operator-required condition —
	// review_spec_gap, review_missing_acceptance, review_too_large at depth
	// cap, or review_unsafe_or_out_of_scope. These classes do not re-enter
	// the automated retry cycle and do not consume the no-progress retry
	// budget; the bead moves to status=proposed until an operator
	// intervenes.
	ExecuteBeadStatusReviewTerminalBlock = "review_terminal_block"

	// ExecuteBeadStatusReviewFixableGap is set when a BLOCK review verdict is
	// classified as a fixable gap — the issues are addressable by a repair
	// attempt at higher MinPower with the reviewer's rationale as context.
	// Exactly one repair cycle is scheduled per result_rev; a second
	// review_fixable_gap on the same result_rev falls through to the regular
	// BLOCK triage path instead.
	ExecuteBeadStatusReviewFixableGap = "review_fixable_gap"

	// ExecuteBeadStatusRepairCycleExhausted is set when the candidate-cycle
	// repair loop reaches its per-attempt repair_max_cycles limit before a
	// reviewer approves the candidate. The latest candidate ref is retained for
	// operator inspection.
	ExecuteBeadStatusRepairCycleExhausted = "repair-cycle-exhausted"
)

// ClassifyExecuteBeadStatus maps a landing outcome to the supervisor-visible
// status contract. This is called by ApplyLandingToResult and by callers who
// build an ExecuteBeadReport from a landing result.
func ClassifyExecuteBeadStatus(outcome string, exitCode int, reason string) string {
	if exitCode != 0 {
		return ExecuteBeadStatusExecutionFailed
	}

	switch outcome {
	case "merged":
		// A merged outcome whose reason carries the push-failure marker
		// means the local target branch advanced but `git push` rejected the
		// new tip (large blob, branch protection, auth, divergence, etc.).
		// Classify these as push_failed so the loop refuses to close the
		// bead and operators are forced to investigate.
		if strings.HasPrefix(reason, PushConflictReasonPrefix) {
			return ExecuteBeadStatusPushConflict
		}
		if strings.HasPrefix(reason, PushFailedReasonPrefix) {
			return ExecuteBeadStatusPushFailed
		}
		return ExecuteBeadStatusSuccess
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return ExecuteBeadStatusNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return ExecuteBeadStatusNoEvidenceProduced
	case "error":
		return ExecuteBeadStatusExecutionFailed
	case "preserved":
		switch {
		case reason == "merge conflict" || reason == "merge failed" || reason == "ff-merge not possible":
			return ExecuteBeadStatusLandConflict
		case reason == "post-run checks failed", strings.HasPrefix(reason, PreMergeChecksReason):
			return ExecuteBeadStatusPostRunCheckFailed
		case reason == RatchetPreserveReason:
			return ExecuteBeadStatusRatchetFailed
		case reason == AttemptIntegrityPreserveReason:
			return ExecuteBeadStatusPreservedNeedsReview
		case reason == OperatorCancelReason:
			return ExecuteBeadStatusPreservedNeedsReview
		}
		if isPreservedNeedsReviewReason(reason) {
			return ExecuteBeadStatusPreservedNeedsReview
		}
		// Preserved iterations may still be success when the caller
		// explicitly requested no merge.
		return ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskSucceeded:
		return ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskFailed:
		return ExecuteBeadStatusExecutionFailed
	default:
		return ExecuteBeadStatusExecutionFailed
	}
}

// IsResourceExhaustedStatus reports whether the status is the stable
// host-resource failure classification.
func IsResourceExhaustedStatus(status string) bool {
	return status == ExecuteBeadStatusResourceExhausted
}

func isPreservedNeedsReviewReason(reason string) bool {
	for _, prefix := range []string{
		"evidence commit failed:",
		"large-deletion gate:",
		"syntax sanity gate:",
		"post-land gate failed:",
	} {
		if strings.HasPrefix(reason, prefix) {
			return true
		}
	}
	return false
}

func ExecuteBeadStatusDetail(status, reason, errMsg string) string {
	switch {
	case reason != "" && errMsg != "" && reason != errMsg:
		return reason + ": " + errMsg
	case reason != "":
		return reason
	case errMsg != "":
		return errMsg
	case status != "":
		return status
	default:
		return "unknown"
	}
}

---
// Package failclass implements the FEAT-004 failure-classification routing
// policy applied by ddx work between bead-execution attempts (bead
// ddx-d27a1895).
//
// It provides four things the queue drain composes:
//
//   - Classify maps a single attempt Outcome to exactly one routing Action,
//     applying the normative failure-classification table.
//   - Escalate owns the single one-hop middle->max tier escalation, which only
//     a typed genuine failure triggers.
//   - Pool enforces a per-pool in-flight max-attempt cap that prevents a
//     multi-worker stampede when many workers fail concurrently.
//   - Pool also carries the global (per-pool, not per-bead) cooldown applied on
//     quota exhaustion.
//
// The classification table is normative; it is inlined here from the bead body
// because the upstream FEAT-004 routing addendum lives in the fizeau repo and
// is not reachable from a cold ddx agent.
package failclass

import (
	"sync"
	"time"
)

// Outcome is the typed result of a single ddx-work attempt. Every Outcome maps
// to exactly one Action via Classify.
type Outcome string

const (
	// OutcomeSuccess: the attempt satisfied the bead's acceptance criteria.
	OutcomeSuccess Outcome = "success"
	// OutcomeAlreadySatisfied: the bead was already satisfied before work.
	OutcomeAlreadySatisfied Outcome = "already_satisfied"
	// OutcomeNoChanges: the agent produced nothing and wrote a rationale.
	OutcomeNoChanges Outcome = "no_changes"
	// OutcomeGenuineFailure: tests fail after real work; acceptance unmet.
	// This is the only outcome that can trigger a tier escalation.
	OutcomeGenuineFailure Outcome = "genuine_failure"
	// OutcomeDirtyWorktree: dirty worktree or partial write.
	OutcomeDirtyWorktree Outcome = "dirty_worktree"
	// OutcomeTransport: provider transport failure (i/o timeout, conn refused,
	// 5xx).
	OutcomeTransport Outcome = "transport"
	// OutcomeQuota: quota exhausted (retry_after).
	OutcomeQuota Outcome = "quota"
	// OutcomeAuth: auth/config missing.
	OutcomeAuth Outcome = "auth"
	// OutcomeSetup: toolchain/setup failure.
	OutcomeSetup Outcome = "setup"
	// OutcomeTimeout: timeout / no-progress watchdog.
	OutcomeTimeout Outcome = "timeout"
	// OutcomeMergeConflict: merge/land conflict.
	OutcomeMergeConflict Outcome = "merge_conflict"
)

// Action is the single routing action selected for an Outcome.
type Action string

const (
	// ActionCloseBead: close the bead (success path).
	ActionCloseBead Action = "close_bead"
	// ActionCloseOrUnclaim: close or unclaim per the agent's rationale; never
	// escalate the tier.
	ActionCloseOrUnclaim Action = "close_or_unclaim"
	// ActionEscalateTier: escalate the tier exactly once (middle->max).
	ActionEscalateTier Action = "escalate_tier"
	// ActionResetRetrySameTier: clean/reset the worktree and retry at the same
	// tier (not an escalation).
	ActionResetRetrySameTier Action = "reset_retry_same_tier"
	// ActionRerouteSameTier: reroute to another dispatchable candidate at the
	// same tier; no tier change.
	ActionRerouteSameTier Action = "reroute_same_tier"
	// ActionGlobalCooldown: put the whole pool to sleep until quota reset; not
	// a per-bead mutation, not an escalation.
	ActionGlobalCooldown Action = "global_cooldown"
	// ActionOperatorAttention: explicit bead state transition to the operator
	// lane (not a notification or an indefinite wait).
	ActionOperatorAttention Action = "operator_attention"
	// ActionUnclaimRetryLater: unclaim and retry later; not an escalation.
	ActionUnclaimRetryLater Action = "unclaim_retry_later"
)

// Escalates reports whether the Action mutates the tier. Only
// ActionEscalateTier escalates; this is the single guard the escalation owner
// (ddx work) checks before calling Escalate.
func (a Action) Escalates() bool {
	return a == ActionEscalateTier
}

// ClassifyContext carries the routing state needed to resolve the tier- and
// attempt-conditional rows of the table (genuine failure and timeout).
type ClassifyContext struct {
	// AtMaxTier reports whether the attempt already ran at the maximum tier. A
	// genuine failure at the max tier goes to the operator lane instead of
	// escalating.
	AtMaxTier bool
	// SameTierRetried reports whether a same-tier retry was already consumed. A
	// second timeout (after one same-tier retry) goes to the operator lane.
	SameTierRetried bool
}

// Classify maps a single attempt Outcome to exactly one Action, applying the
// normative failure-classification table.
//
// Only OutcomeGenuineFailure can produce ActionEscalateTier, and only when the
// attempt was not already at the max tier. The no_changes, dirty, transport,
// quota, auth, setup, timeout, and merge-conflict outcomes never escalate.
func Classify(outcome Outcome, ctx ClassifyContext) Action {
	switch outcome {
	case OutcomeSuccess, OutcomeAlreadySatisfied:
		return ActionCloseBead
	case OutcomeNoChanges:
		return ActionCloseOrUnclaim
	case OutcomeGenuineFailure:
		// Single one-hop middle->max escalation; a max-tier genuine failure
		// stops escalating and goes to the operator lane.
		if ctx.AtMaxTier {
			return ActionOperatorAttention
		}
		return ActionEscalateTier
	case OutcomeDirtyWorktree:
		return ActionResetRetrySameTier
	case OutcomeTransport:
		return ActionRerouteSameTier
	case OutcomeQuota:
		return ActionGlobalCooldown
	case OutcomeAuth, OutcomeSetup:
		return ActionOperatorAttention
	case OutcomeTimeout:
		// Clean + same-tier retry once, then operator-attention.
		if ctx.SameTierRetried {
			return ActionOperatorAttention
		}
		return ActionResetRetrySameTier
	case OutcomeMergeConflict:
		return ActionUnclaimRetryLater
	default:
		// Unknown outcomes go to the operator lane rather than silently
		// escalating or retrying.
		return ActionOperatorAttention
	}
}

// Tier is a routing capability tier. Escalation is a single one-hop edge from
// TierMiddle to TierMax; no other edge escalates.
type Tier int

const (
	// TierLow is the cheapest tier and is never an escalation target.
	TierLow Tier = iota
	// TierMiddle is the default starting tier for dispatch.
	TierMiddle
	// TierMax is the strongest tier and the only escalation target.
	TierMax
)

// Escalate performs the single one-hop middle->max escalation and reports
// whether it changed the tier. Escalation is idempotent: only TierMiddle
// escalates (to TierMax); every other tier — including a tier already at
// TierMax — is returned unchanged with escalated=false. This enforces "exactly
// one middle->max" per dispatch chain.
func Escalate(t Tier) (next Tier, escalated bool) {
	if t == TierMiddle {
		return TierMax, true
	}
	return t, false
}

// Pool tracks per-pool in-flight attempts and the global cooldown for a single
// dispatch pool. It is safe for concurrent use by multiple workers.
//
// The in-flight cap prevents a multi-worker stampede: when many workers fail
// concurrently against the same pool, at most maxInFlight attempts may hold a
// slot at once. The cooldown is global to the pool (applied on quota
// exhaustion), not a per-bead mutation.
type Pool struct {
	mu            sync.Mutex
	name          string
	maxInFlight   int
	inFlight      int
	cooldownUntil time.Time
	now           func() time.Time
}

// NewPool returns a Pool with the given name and in-flight cap. A non-positive
// maxInFlight is clamped to 1. The clock defaults to time.Now and can be
// overridden for tests via SetClock.
func NewPool(name string, maxInFlight int) *Pool {
	if maxInFlight < 1 {
		maxInFlight = 1
	}
	return &Pool{
		name:        name,
		maxInFlight: maxInFlight,
		now:         time.Now,
	}
}

// SetClock overrides the pool's time source. It exists so tests can advance
// time without sleeping; the bead requires bounded, non-hanging tests.
func (p *Pool) SetClock(now func() time.Time) {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.now = now
}

// Name returns the pool's name.
func (p *Pool) Name() string {
	return p.name
}

// Acquire attempts to take one in-flight slot. It returns false when the pool
// is in cooldown or the in-flight cap is already reached; otherwise it takes a
// slot and returns true. Every successful Acquire must be paired with a
// Release.
func (p *Pool) Acquire() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.now().Before(p.cooldownUntil) {
		return false
	}
	if p.inFlight >= p.maxInFlight {
		return false
	}
	p.inFlight++
	return true
}

// Release returns one in-flight slot. It never drops below zero.
func (p *Pool) Release() {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.inFlight > 0 {
		p.inFlight--
	}
}

// InFlight returns the current number of held in-flight slots.
func (p *Pool) InFlight() int {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.inFlight
}

// EnterCooldown applies a global pool cooldown of duration d (typically the
// quota retry_after). It is global to the pool, not a per-bead mutation:
// subsequent Acquire calls fail until the cooldown elapses. A later, longer
// cooldown extends the window; a shorter one never shortens an active window.
func (p *Pool) EnterCooldown(d time.Duration) {
	p.mu.Lock()
	defer p.mu.Unlock()
	until := p.now().Add(d)
	if until.After(p.cooldownUntil) {
		p.cooldownUntil = until
	}
}

// InCooldown reports whether the pool is currently in a global cooldown.
func (p *Pool) InCooldown() bool {

	ensureBeadExtra(b)
	b.Extra[executeLoopNoChangesNextMinPowerKey] = minPower
}

func clearNoChangesNextMinPower(b *bead.Bead) {
	if b.Extra == nil {
		return
	}
	delete(b.Extra, executeLoopNoChangesNextMinPowerKey)
}

func setOrDeleteBeadExtra(extra map[string]any, key, value string) {
	if value == "" {
		delete(extra, key)
		return
	}
	extra[key] = value
}

func clearExecuteLoopNoChangesMetadata(ctx context.Context, store ExecuteBeadLoopStore, beadID string) error {
	return store.Update(ctx, beadID, func(b *bead.Bead) {
		if b.Extra == nil {
			return
		}
		delete(b.Extra, "work-retry-after")
		delete(b.Extra, bead.ExtraCooldownBaseRev)
		delete(b.Extra, "work-last-status")
		delete(b.Extra, "work-last-detail")
		delete(b.Extra, executeLoopSuggestedActionKey)
		delete(b.Extra, executeLoopNoChangesNextMinPowerKey)
		clearSmartRetryMetadata(b)
	})
}

// isValidImplementationAttempt reports whether the given report came from a
// real implementation attempt — one where the implementer had checkout context
// established and a result that can be compared against the base revision for
// no-progress accounting. Returns false for system failures, infrastructure
// issues, intake/scheduling outcomes, review/operator-managed states, and
// other non-implementation outcomes that should not consume the no-progress
// retry budget or trigger long cooldowns.
func isValidImplementationAttempt(report ExecuteBeadReport) bool {
	if report.Disrupted {
		return false
	}
	if isTransientOutcomeReason(report.OutcomeReason) {
		return false
	}
	// Extended system-failure and non-implementation outcome reasons.
	switch report.OutcomeReason {
	case "preflight_failed",
		"intake_block",
		"claim_race",
		"actionable_but_rewritten",
		"too_large_decomposed",
		"intake_error",
		"ambiguous_needs_human",
		FailureModeAuthError,
		FailureModeHarnessNotInstalled,
		FailureModeAgentPowerUnsatisfied,
		FailureModeBlockedByPassthroughConstraint,
		FailureModeNoEvidenceProduced,
		FailureModeWorktreeLost,
		ReadinessSystemReasonResourceExhausted,
		ReadinessSystemReasonRepoConcurrency,
		"operator_required":
		return false
	}
	// Operator/review status codes where the implementer did not run a full
	// implementation pass.
	switch report.Status {
	case ExecuteBeadStatusReviewMalfunction,
		ExecuteBeadStatusDeclinedNeedsDecomposition,
		ExecuteBeadStatusLandConflictOperatorRequired,
		ExecuteBeadStatusReviewTerminalBlock:
		return false
	}
	// Without a BaseRev the implementer never had a commit baseline.
	if report.BaseRev == "" {
		return false
	}
	return true
}

func shouldSuppressNoProgress(report ExecuteBeadReport) bool {
	if !isValidImplementationAttempt(report) {
		return false
	}
	if report.ResultRev == "" {
		return false
	}
	return report.BaseRev == report.ResultRev
}

// mixedCommitCooldownWindow is the lookback period for the mixed_commit circuit-breaker.
const mixedCommitCooldownWindow = 24 * time.Hour

// countRecentMixedCommitEvents returns the number of execute-bead events in the
// store for beadID within window of now that carry the
// mixed_commit_and_no_changes_rationale marker. Used by the circuit-breaker to
// detect a repeated-contradiction loop before the current attempt is appended.
func countRecentMixedCommitEvents(store ExecuteBeadLoopStore, beadID string, window time.Duration, now time.Time) int {
	events, err := store.Events(beadID)
	if err != nil {
		return 0
	}
	cutoff := now.Add(-window)
	count := 0
	for _, ev := range events {
		if ev.Kind == "execute-bead" && ev.CreatedAt.After(cutoff) &&
			strings.Contains(ev.Body, mixedCommitAndNoChangesRationaleReason) {
			count++
		}
	}
	return count
}

func isTransientOutcomeReason(reason string) bool {
	switch reason {
	case "transport", "quota", "routing", "timeout", "merge_conflict",
		ReadinessSystemReasonResourceExhausted,
		ReadinessSystemReasonRepoConcurrency,
		FailureModeLockContention,
		FailureModeNoViableProvider,
		FailureModeServerUnavailable,
		FailureModeWorktreeLost:
		return true
	default:
		return false
	}
}

// isInfraFaultCooldownStatus returns true for work-last-status values that
// represent infra-class failures where time passing (not model/bead work) is
// what resolves the condition. Used by the paused-infra detector to
// distinguish infra-cooled beads from bead-fault-cooled beads.
func isInfraFaultCooldownStatus(status string) bool {
	switch status {
	case FailureModeProviderConnectivity, FailureModeNoViableProvider,
		"loop-error":
		return true
	default:
		return false
	}
}

// infraCooldownResumeAt inspects the IDs in cooldownIDs, gets each bead's
// work-last-status, and returns (earliestRetry, true) when every bead carries
// an infra-fault status. If any bead has a non-infra status or cannot be read,
// it returns (zero, false).
func infraCooldownResumeAt(store ExecuteBeadLoopStore, cooldownIDs []string) (time.Time, bool) {
	var earliest time.Time
	for _, id := range cooldownIDs {
		b, err := store.Get(context.Background(), id)
		if err != nil || b == nil {
			return time.Time{}, false
		}
		status, _ := b.Extra[bead.ExtraLastStatus].(string)
		if !isInfraFaultCooldownStatus(status) {
			return time.Time{}, false
		}
		retryStr, _ := b.Extra[bead.ExtraRetryAfter].(string)
		if retryStr != "" {
			if t, parseErr := time.Parse(time.RFC3339, retryStr); parseErr == nil {
				if earliest.IsZero() || t.Before(earliest) {
					earliest = t
				}
			}
		}
	}
	if earliest.IsZero() {
		earliest = time.Now().UTC().Add(PausedInfraInterval)
	}
	return earliest, true
}

func isNoViableProviderReport(report ExecuteBeadReport) bool {
	if report.OutcomeReason == FailureModeNoViableProvider {
		return true
	}
	combined := strings.TrimSpace(strings.Join([]string{
		report.Detail,
		report.Error,
		report.Stderr,
	}, "\n"))
	return ClassifyFailureMode(report.Status, 0, combined) == FailureModeNoViableProvider
}

// providerConnectivityMarkers names the substrings that indicate the routed
// provider endpoint itself was unreachable (TCP-level dial failure, connection
// refused, network down). These are stricter than the broader transport
// markers because we only treat them as route-exclusion evidence when paired
// with a non-empty Provider in the report.
var providerConnectivityMarkers = []string{
	"dial tcp",
	"connection refused",
	"i/o timeout",
	"no route to host",
	"network is unreachable",
	"bad gateway",
	"service unavailable",
	"gateway timeout",
}

// isProviderConnectivityFailureReport reports whether a worker report describes
// a routed provider endpoint that could not be reached. Requires both an
// identified route (Provider) and a transport-level error marker. Reports that
// already classify as no_viable_provider or routing-infrastructure failures
// keep their own paths; this is for the narrower "fizeau picked a route, the
// HTTP call to that endpoint failed" case.
func isProviderConnectivityFailureReport(report ExecuteBeadReport) bool {
	if report.Status != ExecuteBeadStatusExecutionFailed {
		return false
	}
	if strings.TrimSpace(report.Provider) == "" {
		return false
	}
	if isNoViableProviderReport(report) || isRoutingInfrastructureReport(report) {
		return false
	}
	combined := strings.ToLower(strings.Join([]string{
		report.Detail,
		report.Error,
		report.Stderr,
	}, "\n"))
	for _, marker := range providerConnectivityMarkers {
		if strings.Contains(combined, marker) {
			return true
		}
	}
	return false
}

// providerEndpointURLRe extracts the first http(s) URL from a transport error
// message (e.g. `openai POST http://vidar:1235/v1/chat/completions dial tcp ...`).
// Stops at whitespace or a closing quote so a quoted Go URL error
// (`Post "http://bragi:1234/v1/chat": dial tcp...`) yields the bare URL.
var providerEndpointURLRe = regexp.MustCompile(`https?://[^\s"'\\]+`)

// timeoutClassMarkers orders transport failure classes most-specific first so a
// compound message like "dial tcp ...: i/o timeout" classifies as "i/o timeout"
// rather than the generic "dial tcp" prefix.
var timeoutClassMarkers = []string{
	"connection refused",
	"connection reset",
	"i/o timeout",

// A nil resolveRoute is treated as a no-op and returns false.
func CheckAndApplyRouteExclusions(
	ctx context.Context,
	svc agentlib.FizeauService,
	store ExecuteBeadLoopStore,
	beadID, assignee string,
	extra map[string]any,
	now time.Time,
	minPower int,
	resolveRoute func(ctx context.Context, req agentlib.RouteRequest) (*agentlib.RouteDecision, error),
	nextFloorFn func(int) (int, error),
	timeout time.Duration,
	attemptID string,
	lastActivityAt time.Time,
) (ExecuteBeadReport, bool) {
	if resolveRoute == nil {
		return ExecuteBeadReport{}, false
	}
	failedRoutes := readFailedRoutes(extra)
	excluded := buildExcludedRoutes(failedRoutes, now, RouteExclusionWindow)
	// Never hard-exclude a subscription CLI harness whose binary is on PATH:
	// the failed-route entries replay connectivity blips that must not empty
	// the candidate set during a local-fleet outage (same shield as the
	// tracker-seeding path in service_run.go — single source of truth).
	shielded := shieldedSubscriptionHarnesses(ctx, svc)
	excluded = filterShieldedExcludedRoutes(excluded, shielded)
	if len(excluded) == 0 {
		return ExecuteBeadReport{}, false
	}
	req := agentlib.RouteRequest{
		MinPower:       minPower,
		ExcludedRoutes: excluded,
	}
	if timeout <= 0 {
		timeout = DefaultRouteResolutionTimeout
	}
	_, routeErr, timedOut := resolveRouteBounded(ctx, timeout, resolveRoute, req)
	if timedOut {
		return routeResolutionTimeoutReport(store, beadID, assignee, attemptID, now, timeout, lastActivityAt), true
	}
	if routeErr == nil {
		return ExecuteBeadReport{}, false
	}
	// No viable candidate at minPower with the current exclusions: let the
	// current execution path escalate in-memory rather than persisting a bead
	// retry floor.
	nextFloor := minPower + 1
	if nextFloorFn != nil {
		if floor, err := nextFloorFn(minPower); err == nil {
			nextFloor = floor
		}
	}
	detail := fmt.Sprintf(
		"ResolveRoute: no viable routing candidate: all routes at power %d excluded by recent failures; escalating current retry floor to %d",
		minPower, nextFloor,
	)
	return ExecuteBeadReport{
		BeadID:        beadID,
		Status:        ExecuteBeadStatusExecutionFailed,
		Detail:        detail,
		OutcomeReason: FailureModeNoViableProvider,
	}, true
}

// isOperatorRoutingPinned reports whether the resolved passthrough envelope
// carries any explicit operator pin (harness, model, or provider). When true,
// the route-exclusion path records the failure but does not bump the power
// hint — pinned routes must retry exactly as the operator requested.
func isOperatorRoutingPinned(pt config.AgentPassthrough) bool {
	return strings.TrimSpace(pt.Harness) != "" ||
		strings.TrimSpace(pt.Model) != "" ||
		strings.TrimSpace(pt.Provider) != ""
}

// applyProviderConnectivityRouteExclusion appends the failed (provider, model)
// to the bead's failed-route list. The lifecycle status is unchanged (bead
// stays open). Retry power escalation is derived from route-failure evidence
// in the current execution path rather than a persisted bead floor.
//
// When the ladder is exhausted, it emits an execution-escalation-aborted event.
// Repeated provider connectivity failures remain retryable route-health
// evidence: the bead stays open and Fizeau receives recent failed routes so it
// can pick another viable route without blocking the dependency tree behind an
// operator-attention state.
func applyProviderConnectivityRouteExclusion(
	store ExecuteBeadLoopStore,
	beadID string,
	actor string,
	report ExecuteBeadReport,
	operatorPinned bool,
	nextFloorFn func(int) (int, error),
	at time.Time,
) error {
	var (
		repeatFailure bool
		repeatCount   int
	)
	endpoint, timeoutClass := parseProviderConnectivityFacts(report)
	if err := store.Update(context.Background(), beadID, func(b *bead.Bead) {
		existing := readFailedRoutes(b.Extra)
		for _, e := range existing {
			if e.Provider == report.Provider && e.Model == report.Model {
				repeatFailure = true
				repeatCount = e.Count + 1
				break
			}
		}
		appendFailedRoute(b, FailedRouteEntry{
			Provider:     report.Provider,
			Model:        report.Model,
			ActualPower:  report.ActualPower,
			Reason:       FailureModeProviderConnectivity,
			Endpoint:     endpoint,
			TimeoutClass: timeoutClass,
			At:           at.UTC().Format(time.RFC3339),
		})
	}); err != nil {
		return err
	}
	if repeatFailure {
		body, _ := json.Marshal(map[string]any{
			"provider":      report.Provider,
			"model":         report.Model,
			"actual_power":  report.ActualPower,
			"count":         repeatCount,
			"reason":        FailureModeProviderConnectivity,
			"endpoint":      endpoint,
			"timeout_class": timeoutClass,
			"action":        "keep_open_for_autonomous_retry",
		})
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "provider_connectivity.auto_retry",
			Summary:   "repeated provider connectivity failure kept open for autonomous retry",
			Body:      string(body),
			Actor:     actor,
			Source:    "ddx work",
			CreatedAt: at,
		})
	}
	return nil
}

func autoReopenRetryableProviderConnectivityProposals(
	ctx context.Context,
	store ExecuteBeadLoopStore,
	actor string,
	at time.Time,
	emit func(string, map[string]any),
) (int, error) {
	if err := ctx.Err(); err != nil {
		return 0, err
	}
	proposedStore, ok := store.(proposedOperatorAttentionStore)
	if !ok {
		return 0, nil
	}
	proposed, err := proposedStore.ProposedOperatorAttention()
	if err != nil {
		return 0, err
	}
	var reopened int
	for _, b := range proposed {
		if !isRetryableProviderConnectivityProposal(b) {
			continue
		}
		if err := store.UpdateWithLifecycleStatus(b.ID, bead.StatusOpen, bead.LifecycleTransitionOptions{
			Reason: "provider connectivity failure is retryable route evidence; reopening for autonomous fallback",
			Source: "ddx work",
			Actor:  actor,
		}, func(b *bead.Bead) error {
			ensureBeadExtra(b)
			b.Labels = removeBeadLabels(b.Labels, bead.LabelNeedsHuman, bead.LabelNeedsInvestigation)
			bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{})
			return nil
		}); err != nil {
			return reopened, err
		}
		body, _ := json.Marshal(map[string]any{
			"reason": "provider_connectivity",
			"action": "reopen_for_autonomous_retry",
		})
		_ = store.AppendEvent(b.ID, bead.BeadEvent{
			Kind:      "provider_connectivity.auto_reopen",
			Summary:   "reopened provider-connectivity operator-attention bead for autonomous retry",
			Body:      string(body),
			Actor:     actor,
			Source:    "ddx work",
			CreatedAt: at,
		})
		if emit != nil {
			emit("provider_connectivity.auto_reopen", map[string]any{
				"bead_id": b.ID,
				"reason":  "provider_connectivity",
			})
		}
		reopened++
	}
	return reopened, nil
}

func isRetryableProviderConnectivityProposal(b bead.Bead) bool {
	if b.Status != bead.StatusProposed {
		return false
	}
	meta := bead.GetNeedsHumanMeta(b)
	text := strings.ToLower(strings.Join([]string{
		meta.Reason,
		meta.Summary,
		meta.SuggestedAction,
		meta.Source,
	}, "\n"))
	if !strings.Contains(text, "provider") {
		return false
	}
	return strings.Contains(text, "provider_connectivity") ||
		strings.Contains(text, "provider unreachable") ||
		strings.Contains(text, "unreachable on 2+ attempts") ||
		strings.Contains(text, "connectivity")
}

// emitEscalationAbortedEvent records a kind=execution-escalation-aborted event
// when nextFloorFn returns an error (typically ErrLadderExhausted). Best-effort.
func emitEscalationAbortedEvent(store BeadEventAppender, beadID, actor, provider, model string, actualPower int, at time.Time) {
	if store == nil || beadID == "" {
		return
	}
	summary := fmt.Sprintf("escalation aborted: ladder exhausted at power %d provider=%s", actualPower, provider)
	if model != "" {
		summary += " model=" + model
	}
	appendWorkEvent(store, beadID, "execution-escalation-aborted", summary, map[string]any{
		"provider":     provider,
		"model":        model,
		"actual_power": actualPower,
		"reason":       fmt.Sprintf("ladder exhausted at power %d", actualPower),
	}, actor, at)
}

// emitRouteFailureEvent records a kind=route-failure event capturing the
// failed (provider, model) tuple and the surface error. Best-effort.
func emitRouteFailureEvent(store BeadEventAppender, beadID, actor string, report ExecuteBeadReport, at time.Time) {
	if store == nil || beadID == "" {
		return
	}
	endpoint, timeoutClass := parseProviderConnectivityFacts(report)
	summary := "provider=" + report.Provider
	if report.Model != "" {
		summary += " model=" + report.Model
	}
	if endpoint != "" {
		summary += " endpoint=" + endpoint
	}
	if timeoutClass != "" {
		summary += " (" + timeoutClass + ")"
	}
	summary += " connectivity failure"
	appendWorkEvent(store, beadID, "route-failure", summary, map[string]any{
		"provider":       report.Provider,
		"model":          report.Model,
		"harness":        report.Harness,
		"actual_power":   report.ActualPower,
		"endpoint":       endpoint,
		"timeout_class":  timeoutClass,
		"detail":         report.Detail,
		"error":          report.Error,
		"outcome_reason": FailureModeProviderConnectivity,
	}, actor, at)
}

func isRoutingInfrastructureReport(report ExecuteBeadReport) bool {
	if report.Status != ExecuteBeadStatusExecutionFailed {
		return false
	}
	combined := strings.TrimSpace(strings.Join([]string{
		report.Detail,
		report.Error,
		report.Stderr,
	}, "\n"))
	if combined == "" {
		return false
	}
	lower := strings.ToLower(combined)
	return containsAny(lower,
		"resolveroute:",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint")
}

