		return false
	}
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "post-attempt decomposition: bead %s split into %s\n", candidate.ID, strings.Join(childIDs, ", "))
	}
	emit("post_attempt_decomposition.applied", map[string]any{
		"bead_id":   candidate.ID,
		"child_ids": childIDs,
